import com.alibaba.nacos.config.server.utils.ZipUtils;

import java.io.ByteArrayOutputStream;
import java.nio.charset.StandardCharsets;
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;

public class NacosZipMetaDataRepro {
    public static void main(String[] args) throws Exception {
        byte[] zip = createZip();
        ZipUtils.UnZipResult result = ZipUtils.unzip(zip);
        if (result.getMetaDataItem() == null) {
            throw new IllegalStateException("meta_data was not recognized; import parser would dereference null metadata");
        }
        System.out.println("metadata=" + result.getMetaDataItem().getItemName());
        System.out.println("items=" + result.getZipItemList().size());
    }

    private static byte[] createZip() throws Exception {
        ByteArrayOutputStream byteOut = new ByteArrayOutputStream();
        try (ZipOutputStream zipOut = new ZipOutputStream(byteOut)) {
            zipOut.putNextEntry(new ZipEntry("DEFAULT_GROUP/application.yml"));
            zipOut.write("spring:\n  application:\n    name: demo\n".getBytes(StandardCharsets.UTF_8));
            zipOut.closeEntry();
            zipOut.putNextEntry(new ZipEntry("meta_data"));
            zipOut.write("DEFAULT_GROUP|application.yml|\n".getBytes(StandardCharsets.UTF_8));
            zipOut.closeEntry();
        }
        return byteOut.toByteArray();
    }
}
EOF
