     * unzip method.
     */
    public static UnZipResult unzip(byte[] source) {
        List<ZipItem> itemList = new ArrayList<>();
        ZipItem metaDataItem = null;
        try (ZipInputStream zipIn = new ZipInputStream(new ByteArrayInputStream(source))) {
            ZipEntry entry;
            while ((entry = zipIn.getNextEntry()) != null) {
                if (entry.isDirectory()) {
                    continue;
                }
                try (ByteArrayOutputStream out = new ByteArrayOutputStream()) {
                    byte[] buffer = new byte[1024];
                    int offset;
                    while ((offset = zipIn.read(buffer)) != -1) {
                        out.write(buffer, 0, offset);
                    }
                    String entryName = entry.getName();
                    String entryData = out.toString("UTF-8");
                    if (isMetaDataEntry(entryName)) {
                        if (metaDataItem == null || getMetaDataPriority(entryName) > getMetaDataPriority(
                                metaDataItem.getItemName())) {
                            metaDataItem = new ZipItem(entryName, entryData);
                        }
                        continue;
                    }
                    itemList.add(new ZipItem(entryName, entryData));
                } catch (IOException e) {
                    LOGGER.error("unzip error", e);
                }
            }
        } catch (IOException e) {
            LOGGER.error("unzip error", e);
        }
        return new UnZipResult(itemList, metaDataItem);
    }

    private static boolean isMetaDataEntry(String entryName) {
        return Constants.CONFIG_EXPORT_METADATA_NEW.equals(entryName) || Constants.CONFIG_EXPORT_METADATA.equals(entryName)
                || Constants.CONFIG_EXPORT_METADATA_COMPATIBLE.equals(entryName);
    }

    private static int getMetaDataPriority(String entryName) {
        if (Constants.CONFIG_EXPORT_METADATA_NEW.equals(entryName)) {
            return 3;
        }
        if (Constants.CONFIG_EXPORT_METADATA.equals(entryName)) {
            return 2;
        }
        if (Constants.CONFIG_EXPORT_METADATA_COMPATIBLE.equals(entryName)) {
            return 1;
        }
        return 0;
    }

}

