import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Locale;
import java.util.Map;

/**
 * Utilities for config import/export metadata.
 *
 * @author Nacos
 */
public final class ConfigMetadataUtils {

    private static final String LEGACY_META_APP_SUFFIX = ".app";

    private ConfigMetadataUtils() {
    }

    /**
     * Parse import metadata from supported ZIP metadata formats.
     *
     * @param unziped unzip result
     * @return parsed config metadata, or null when metadata is missing or invalid
     */
    public static ConfigMetadata parseMetadata(ZipUtils.UnZipResult unziped) {
        if (unziped == null || unziped.getMetaDataItem() == null) {
            return null;
        }
        ZipUtils.ZipItem metaDataItem = unziped.getMetaDataItem();
        String metaData = metaDataItem.getItemData();
        if (StringUtils.isBlank(metaData)) {
            return null;
        }
        if (Constants.CONFIG_EXPORT_METADATA_COMPATIBLE.equals(metaDataItem.getItemName())) {
            return parseCompatibleMetadata(metaData);
        }
        if (Constants.CONFIG_EXPORT_METADATA.equals(metaDataItem.getItemName())) {
            return parseLegacyMetadata(unziped, metaData);
        }
        return YamlParserUtil.loadObject(metaData, ConfigMetadata.class);
    }

    /**
     * Build the console compatible meta_data file content.
     *
     * @param dataList exported config data
     * @return meta_data file content
     */
    public static String buildCompatibleMetadata(List<ConfigAllInfo> dataList) {
        StringBuilder result = new StringBuilder();
        for (ConfigAllInfo config : dataList) {
            result.append(config.getGroup()).append('|').append(config.getDataId()).append('|')
                    .append(config.getTenant() == null ? "" : config.getTenant()).append('\n');
        }
        return result.toString();
    }

    private static ConfigMetadata parseCompatibleMetadata(String metaData) {
        ConfigMetadata configMetadata = new ConfigMetadata();
        List<ConfigMetadata.ConfigExportItem> metadata = new ArrayList<>();
        for (String line : metaData.split("\\R")) {
            if (StringUtils.isBlank(line)) {
                continue;
            }
            String[] items = line.split("\\|", -1);
            if (items.length < 2) {
                return null;
            }
            ConfigMetadata.ConfigExportItem exportItem = new ConfigMetadata.ConfigExportItem();
            exportItem.setGroup(items[0]);
            exportItem.setDataId(items[1]);
            exportItem.setType(inferType(items[1]));
            metadata.add(exportItem);
        }
        configMetadata.setMetadata(metadata);
        return configMetadata;
    }

    private static ConfigMetadata parseLegacyMetadata(ZipUtils.UnZipResult unziped, String metaData) {
        Map<String, String> appNames = parseLegacyAppNames(metaData);
        ConfigMetadata configMetadata = new ConfigMetadata();
        List<ConfigMetadata.ConfigExportItem> metadata = new ArrayList<>();
        int itemNameLength = 2;
        for (ZipUtils.ZipItem zipItem : unziped.getZipItemList()) {
            String[] groupAndDataId = zipItem.getItemName().split(Constants.CONFIG_EXPORT_ITEM_FILE_SEPARATOR);
            if (groupAndDataId.length != itemNameLength) {
                continue;
            }
            String group = groupAndDataId[0];
            String dataId = groupAndDataId[1];
            ConfigMetadata.ConfigExportItem exportItem = new ConfigMetadata.ConfigExportItem();
            exportItem.setGroup(group);
            exportItem.setDataId(dataId);
            exportItem.setType(inferType(dataId));
            exportItem.setAppName(appNames.get(packageLegacyMetaName(group, dataId)));
            metadata.add(exportItem);
        }
        configMetadata.setMetadata(metadata);
        return configMetadata;
    }

    private static Map<String, String> parseLegacyAppNames(String metaData) {
        Map<String, String> result = new HashMap<>(16);
        for (String line : metaData.split("\\R")) {
            if (StringUtils.isBlank(line)) {
                continue;
            }
            String[] items = line.split("=", 2);
            if (items.length == 2) {
                result.put(items[0], items[1]);
            }
        }
        return result;
    }

    private static String packageLegacyMetaName(String group, String dataId) {
        String tempDataId = dataId;
        int lastDotIndex = tempDataId.lastIndexOf('.');
        if (lastDotIndex > -1) {
            tempDataId = tempDataId.substring(0, lastDotIndex) + "~" + tempDataId.substring(lastDotIndex + 1);
        }
        return group + "." + tempDataId + LEGACY_META_APP_SUFFIX;
    }

    private static String inferType(String dataId) {
        int lastDotIndex = dataId.lastIndexOf('.');
        if (lastDotIndex > -1 && lastDotIndex < dataId.length() - 1) {
            String suffix = dataId.substring(lastDotIndex + 1).toLowerCase(Locale.ROOT);
            if ("yml".equals(suffix)) {
                return ConfigType.YAML.getType();
            }
            if (ConfigType.isValidType(suffix)) {
                return suffix;
            }
        }
        return ConfigType.getDefaultType().getType();
    }
}

