import com.alibaba.nacos.config.server.constant.Constants;
import com.alibaba.nacos.config.server.model.ConfigMetadata;
import com.alibaba.nacos.config.server.utils.ConfigMetadataUtils;
import com.alibaba.nacos.config.server.utils.ZipUtils;

import java.io.ByteArrayOutputStream;
import java.nio.charset.StandardCharsets;
import java.util.Arrays;
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;

public class NacosZipMetaDataRepro {
    public static void main(String[] args) throws Exception {
        verifyCompatibleMetaDataImport();
        verifyMetadataPriorityAndSkipping();
        System.out.println("temporary repro passed");
    }

    private static void verifyCompatibleMetaDataImport() throws Exception {
        ZipUtils.UnZipResult result = ZipUtils.unzip(createZip(
                entry("DEFAULT_GROUP/application.yml", "spring:\n  application:\n    name: demo\n"),
                entry(Constants.CONFIG_EXPORT_METADATA_COMPATIBLE, "DEFAULT_GROUP|application.yml|\n")));
        require(result.getMetaDataItem() != null, "meta_data should be recognized");
        require(Constants.CONFIG_EXPORT_METADATA_COMPATIBLE.equals(result.getMetaDataItem().getItemName()),
                "meta_data should be selected when it is the only metadata entry");
        require(result.getZipItemList().size() == 1, "metadata entry should not be treated as config content");

        ConfigMetadata metadata = ConfigMetadataUtils.parseMetadata(result);
        require(metadata != null && metadata.getMetadata().size() == 1, "meta_data should parse to one metadata item");
        ConfigMetadata.ConfigExportItem item = metadata.getMetadata().get(0);
        require("DEFAULT_GROUP".equals(item.getGroup()), "group should parse from meta_data");
        require("application.yml".equals(item.getDataId()), "dataId should parse from meta_data");
        require("yaml".equals(item.getType()), "yml dataId should infer yaml type");
    }

    private static void verifyMetadataPriorityAndSkipping() throws Exception {
        ZipUtils.UnZipResult result = ZipUtils.unzip(createZip(
                entry("DEFAULT_GROUP/application.yml", "content"),
                entry(Constants.CONFIG_EXPORT_METADATA_COMPATIBLE, "DEFAULT_GROUP|application.yml|\n"),
                entry(Constants.CONFIG_EXPORT_METADATA_NEW, "metadata:\n- dataId: application.yml\n  group: DEFAULT_GROUP\n  type: yaml\n")));
        require(Constants.CONFIG_EXPORT_METADATA_NEW.equals(result.getMetaDataItem().getItemName()),
                ".metadata.yml should remain preferred when both metadata formats are present");
        require(result.getZipItemList().size() == 1, "all metadata entries should be skipped from config content");
    }

    private static NamedEntry entry(String name, String data) {
        return new NamedEntry(name, data);
    }

    private static byte[] createZip(NamedEntry... entries) throws Exception {
        ByteArrayOutputStream byteOut = new ByteArrayOutputStream();
        try (ZipOutputStream zipOut = new ZipOutputStream(byteOut)) {
            for (NamedEntry entry : Arrays.asList(entries)) {
                zipOut.putNextEntry(new ZipEntry(entry.name));
                zipOut.write(entry.data.getBytes(StandardCharsets.UTF_8));
                zipOut.closeEntry();
            }
        }
        return byteOut.toByteArray();
    }

    private static void require(boolean condition, String message) {
        if (!condition) {
            throw new IllegalStateException(message);
        }
    }

    private static final class NamedEntry {
        private final String name;
        private final String data;

        private NamedEntry(String name, String data) {
            this.name = name;
            this.data = data;
        }
    }
}
